import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as s,d as n}from"./app-75fed8c6.js";const c={},i=n(`<h2 id="cd" tabindex="-1"><a class="header-anchor" href="#cd" aria-hidden="true">#</a> cd</h2><p>命令用于改变当前工作目录的命令，切换到指定的路径。</p><p>若目录名称省略，则变换至使用者的 home 目录 (也就是刚 login 时所在的目录)。</p><p><code>~</code>也表示为 home 目录 的意思，<code>.</code>则是表示目前所在的目录，<code>..</code>则表示目前目录位置的上一层目录。</p><h4 id="语法" tabindex="-1"><a class="header-anchor" href="#语法" aria-hidden="true">#</a> 语法</h4><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token builtin class-name">cd</span> <span class="token punctuation">[</span>dirName<span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li><code>dirName</code>：要切换的目标目录，可以是相对路径或绝对路径。</li></ul><h2 id="pwd" tabindex="-1"><a class="header-anchor" href="#pwd" aria-hidden="true">#</a> pwd</h2><p>命令用于显示工作目录。</p><p>执行<code>pwd</code>指令可立刻得知您目前所在的工作目录的绝对路径名称。</p><h4 id="语法-1" tabindex="-1"><a class="header-anchor" href="#语法-1" aria-hidden="true">#</a> 语法</h4><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token builtin class-name">pwd</span> <span class="token punctuation">[</span>--help<span class="token punctuation">]</span><span class="token punctuation">[</span>--version<span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li>--help 在线帮助。</li><li>--version 显示版本信息。</li></ul><h2 id="ls" tabindex="-1"><a class="header-anchor" href="#ls" aria-hidden="true">#</a> ls</h2><p>命令用于显示指定工作目录下之内容（列出目前工作目录所含的文件及子目录）。</p><h4 id="语法-2" tabindex="-1"><a class="header-anchor" href="#语法-2" aria-hidden="true">#</a> 语法</h4><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">ls</span> <span class="token punctuation">[</span>-alrtAFR<span class="token punctuation">]</span> <span class="token punctuation">[</span>name<span class="token punctuation">..</span>.<span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li><code>-a</code> 显示所有文件及目录 (<code>.</code>开头的隐藏文件也会列出)</li><li><code>-d</code> 只列出目录（不递归列出目录内的文件）。</li><li><code>-l</code> 以长格式显示文件和目录信息，包括权限、所有者、大小、创建时间等。</li><li><code>-r</code> 倒序显示文件和目录。</li><li><code>-t</code> 将按照修改时间排序，最新的文件在最前面。</li><li><code>-A</code> 同<code>-a</code>，但不列出<code>.</code>(目前目录) 及<code>..</code>(父目录)</li><li><code>-F</code> 在列出的文件名称后加一符号；例如可执行档则加<code>\\*</code>, 目录则加<code>/</code></li><li><code>-R</code> 递归显示目录中的所有文件和子目录。</li></ul><h4 id="实例" tabindex="-1"><a class="header-anchor" href="#实例" aria-hidden="true">#</a> 实例</h4><p>当文件名包含空格、特殊字符或者开始字符为破折号时，可以使用反斜杠（<code>\\</code>）进行转义，或者使用引号将文件名括起来。例如：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">ls</span> <span class="token string">&quot;my file.txt&quot;</span>    <span class="token comment"># 列出文件名为&quot;my file.txt&quot;的文件</span>
<span class="token function">ls</span> my<span class="token punctuation">\\</span> file.txt     <span class="token comment"># 列出文件名为&quot;my file.txt&quot;的文件</span>
<span class="token function">ls</span> -- <span class="token parameter variable">-filename</span>     <span class="token comment"># 列出文件名为&quot;-filename&quot;的文件</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>ls</code>命令还可以使用通配符进行模式匹配，例如 <code>\\*</code> 表示匹配任意字符，<code>?</code>表示匹配一个字符。例如：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">ls</span> *.txt         <span class="token comment"># 列出所有扩展名为.txt的文件</span>
<span class="token function">ls</span> file?.txt     <span class="token comment"># 列出文件名为file?.txt的文件，其中?表示任意一个字符</span>
<span class="token function">ls</span> <span class="token punctuation">[</span>abc<span class="token punctuation">]</span>*.txt    <span class="token comment"># 列出以a、b或c开头、扩展名为.txt的文件</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>列出目前工作目录下所有名称是<code>s</code>开头的文件，越新的排越后面:</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">ls</span> <span class="token parameter variable">-ltr</span> s*
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="mkdir" tabindex="-1"><a class="header-anchor" href="#mkdir" aria-hidden="true">#</a> mkdir</h2><p>命令用于创建目录。</p><h4 id="语法-3" tabindex="-1"><a class="header-anchor" href="#语法-3" aria-hidden="true">#</a> 语法</h4><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">mkdir</span> <span class="token punctuation">[</span>-p<span class="token punctuation">]</span> dirName
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li><code>-p</code>确保目录名称存在，不存在的就建一个。</li></ul><h4 id="实例-1" tabindex="-1"><a class="header-anchor" href="#实例-1" aria-hidden="true">#</a> 实例</h4><p>在工作目录下，建立一个名为<code>runoob</code>的子目录 :</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">mkdir</span> runoob
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>在工作目录下的<code>runoob2</code>目录中，建立一个名为<code>test</code>的子目录。</p><p>若<code>runoob2</code>目录原本不存在，则建立一个。（注：本例若不加<code>-p</code>参数，且原本<code>runoob2</code>目录不存在，则产生错误。）</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">mkdir</span> <span class="token parameter variable">-p</span> runoob2/test
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="rmdir" tabindex="-1"><a class="header-anchor" href="#rmdir" aria-hidden="true">#</a> rmdir</h2><p>命令用于删除空目录。</p><h4 id="语法-4" tabindex="-1"><a class="header-anchor" href="#语法-4" aria-hidden="true">#</a> 语法</h4><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">rmdir</span> <span class="token punctuation">[</span>-p<span class="token punctuation">]</span> dirName
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li><code>-p</code>是当子目录被删除后使它也成为空目录的话，则顺便一并删除。</li></ul><h4 id="实例-2" tabindex="-1"><a class="header-anchor" href="#实例-2" aria-hidden="true">#</a> 实例</h4><p>将工作目录下，名为<code>AAA</code>的子目录删除</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">rmdir</span> AAA
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>在工作目录下的<code>BBB</code>目录中，删除名为<code>Test</code>的子目录。若<code>Test</code>删除后，<code>BBB</code>目录成为空目录，则<code>BBB</code>亦予删除</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">rmdir</span> <span class="token parameter variable">-p</span> BBB/Test
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="touch" tabindex="-1"><a class="header-anchor" href="#touch" aria-hidden="true">#</a> touch</h2><p>用于修改文件或者目录的时间属性，包括存取时间和更改时间。若文件不存在，系统会建立一个新的文件。</p><h4 id="语法-5" tabindex="-1"><a class="header-anchor" href="#语法-5" aria-hidden="true">#</a> 语法</h4><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">touch</span> <span class="token punctuation">[</span>-acfm<span class="token punctuation">]</span><span class="token punctuation">[</span>-d<span class="token operator">&lt;</span>日期时间<span class="token operator">&gt;</span><span class="token punctuation">]</span><span class="token punctuation">[</span>-r<span class="token operator">&lt;</span>参考文件或目录<span class="token operator">&gt;</span><span class="token punctuation">]</span> <span class="token punctuation">[</span>-t<span class="token operator">&lt;</span>日期时间<span class="token operator">&gt;</span><span class="token punctuation">]</span><span class="token punctuation">[</span>--help<span class="token punctuation">]</span><span class="token punctuation">[</span>--version<span class="token punctuation">]</span><span class="token punctuation">[</span>文件或目录…<span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li><code>a</code>改变档案的读取时间记录。</li><li><code>m</code>改变档案的修改时间记录。</li><li><code>c</code>假如目的档案不存在，不会建立新的档案。与<code>--no-create</code>的效果一样。</li><li><code>f</code>不使用，是为了与其他<code>unix</code>系统的相容性而保留。</li><li><code>r</code>使用参考档的时间记录，与<code>--file</code>的效果一样。</li><li><code>d</code>设定时间与日期，可以使用各种不同的格式。</li><li><code>t</code>设定档案的时间记录，格式与<code>date</code>指令相同。</li><li><code>--no-create</code>不会建立新档案。</li><li><code>--help</code>列出指令格式。</li><li><code>--version</code>列出版本讯息。</li></ul><h2 id="cat" tabindex="-1"><a class="header-anchor" href="#cat" aria-hidden="true">#</a> cat</h2><p>作用是用于查看和连接文件。</p><h4 id="语法-6" tabindex="-1"><a class="header-anchor" href="#语法-6" aria-hidden="true">#</a> 语法</h4><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">cat</span> <span class="token punctuation">[</span>选项<span class="token punctuation">]</span> <span class="token punctuation">[</span>文件<span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li>参数说明： <ul><li><code>-n</code>：显示行号，会在输出的每一行前加上行号。</li><li><code>-b</code>：显示行号，但只对非空行进行编号。</li><li><code>-s</code>：压缩连续的空行，只显示一个空行。</li><li><code>-E</code>：在每一行的末尾显示<code>$</code>符号。</li><li><code>-T</code>：将<code>Tab</code>字符显示为<code>^I</code>。</li><li><code>-v</code>：显示一些非打印字符。</li></ul></li><li>使用说明： <ul><li>显示文件内容：<code>cat filename</code>会将指定文件的内容输出到终端上。</li><li>连接文件：<code>cat file1 file2 &gt; combined_file</code>可以将<code>file1</code>和<code>file2</code>的内容连接起来，并将结果输出到<code>combined_file</code>中。</li><li>创建文件：可以使用<code>cat</code>命令来创建文件，例如<code>cat &gt; filename</code>，然后你可以输入文本，按<code>Ctrl+D</code>来保存并退出。</li><li>在终端显示文件：可以将<code>cat</code>与管道<code>|</code>结合使用，用来显示其他命令的输出，例如<code>ls -l | cat</code>会将<code>ls -l</code>的输出通过<code>cat</code>打印到终端上。</li></ul></li></ul><h4 id="实例-3" tabindex="-1"><a class="header-anchor" href="#实例-3" aria-hidden="true">#</a> 实例</h4><p>查看文件内容：显示文件<code>filename</code>的内容。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">cat</span> filename
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>创建文件：将标准输入重定向到文件<code>filename</code>，覆盖该文件的内容。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">cat</span> <span class="token operator">&gt;</span> filename
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>追加内容到文件：将标准输入追加到文件<code>filename</code>的末尾。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">cat</span> <span class="token operator">&gt;&gt;</span> filename
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>连接文件：将<code>file1</code>和<code>file2</code>的内容合并到<code>file3</code>中。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">cat</span> file1 file2 <span class="token operator">&gt;</span> file3
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>显示多个文件的内容：同时显示<code>file1</code>和<code>file2</code>的内容。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">cat</span> file1 file2
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>使用管道：将<code>cat</code>命令的输出作为另一个命令的输入。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">cat</span> filename <span class="token operator">|</span> <span class="token builtin class-name">command</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>查看文件的最后几行：显示文件<code>filename</code>的最后 10 行。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">cat</span> filename <span class="token operator">|</span> <span class="token function">tail</span> <span class="token parameter variable">-n</span> <span class="token number">10</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>使用<code>-n</code>选项显示行号：显示文件<code>filename</code>的内容，并在每行的前面加上行号。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">cat</span> <span class="token parameter variable">-n</span> filename
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>使用<code>-b</code>选项仅显示非空行的行号：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">cat</span> <span class="token parameter variable">-b</span> filename
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>使用<code>-s</code>选项合并空行：显示文件<code>filename</code>的内容，并合并连续的空行。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">cat</span> <span class="token parameter variable">-s</span> filename
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>使用<code>-t</code>选项显示制表符：显示文件<code>filename</code>的内容，并用<code>^I</code>表示制表符。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">cat</span> <span class="token parameter variable">-t</span> filename
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>使用<code>-e</code>选项显示行结束符：显示文件<code>filename</code>的内容，并用<code>$</code>表示行结束。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">cat</span> <span class="token parameter variable">-e</span> filename
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>把<code>textfile1</code>的文档内容加上行号后输入<code>textfile2</code>这个文档里：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">cat</span> <span class="token parameter variable">-n</span> textfile1 <span class="token operator">&gt;</span> textfile2
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>把<code>textfile1</code>和<code>textfile2</code>的文档内容加上行号（空白行不加）之后将内容附加到<code>textfile3</code>文档里：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">cat</span> <span class="token parameter variable">-b</span> textfile1 textfile2 <span class="token operator">&gt;&gt;</span> textfile3
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="more" tabindex="-1"><a class="header-anchor" href="#more" aria-hidden="true">#</a> more</h2><p>Linux<code>more</code>命令类似<code>cat</code>，不过会以一页一页的形式显示，更方便使用者逐页阅读，而最基本的指令就是按空白键<code>space</code>就往下一页显示，按<code>b</code>键就会往回<code>back</code>一页显示，而且还有搜寻字串的功能（与<code>vi</code>相似）</p><h4 id="语法-7" tabindex="-1"><a class="header-anchor" href="#语法-7" aria-hidden="true">#</a> 语法</h4><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">more</span> <span class="token punctuation">[</span>-dlfpcsu<span class="token punctuation">]</span> <span class="token punctuation">[</span>-num<span class="token punctuation">]</span> <span class="token punctuation">[</span>+/pattern<span class="token punctuation">]</span> <span class="token punctuation">[</span>+linenum<span class="token punctuation">]</span> <span class="token punctuation">[</span>fileNames<span class="token punctuation">..</span><span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li>参数 <ul><li><code>-num</code> 一次显示的行数</li><li><code>-d</code> 提示使用者，在画面下方显示 [Press space to continue, &#39;q&#39; to quit.] ，如果使用者按错键，则会显示 [Press &#39;h&#39; for instructions.] 而不是 &#39;哔&#39; 声</li><li><code>-l</code> 取消遇见特殊字元<code>^L</code>时会暂停的功能</li><li><code>-f</code> 计算行数时，以实际上的行数，而非自动换行过后的行数（有些单行字数太长的会被扩展为两行或两行以上）</li><li><code>-p</code> 不以卷动的方式显示每一页，而是先清除萤幕后再显示内容</li><li><code>-c</code> 跟 -p 相似，不同的是先显示内容再清除其他旧资料</li><li><code>-s</code> 当遇到有连续两行以上的空白行，就代换为一行的空白行</li><li><code>-u</code> 不显示下引号 （根据环境变数 TERM 指定的 terminal 而有所不同）</li><li><code>+/pattern</code> 在每个文档显示前搜寻该字串，然后从该字串之后开始显示</li><li><code>+num</code> 从第<code>num</code>行开始显示</li><li><code>fileNames</code> 欲显示内容的文档，可为复数个数</li></ul></li><li>操作命令 <ul><li><code>Enter</code>向下 n 行，需要定义,默认为 1 行</li><li><code>Ctrl+F</code>向下滚动一屏</li><li><code>空格键</code>向下滚动一屏</li><li><code>Ctrl+B</code>返回上一屏</li><li><code>=</code>输出当前行的行号</li><li><code>：f</code> 输出文件名和当前行的行号</li><li><code>V</code>调用 vi 编辑器</li><li><code>!</code>命令 调用 Shell，并执行命令</li><li><code>q</code>退出 more</li></ul></li></ul><h4 id="实例-4" tabindex="-1"><a class="header-anchor" href="#实例-4" aria-hidden="true">#</a> 实例</h4><p>逐页显示<code>testfile</code>文档内容，如有连续两行以上空白行则以一行空白行显示。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">more</span> <span class="token parameter variable">-s</span> testfile
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>从第 20 行开始显示<code>testfile</code>之文档内容。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">more</span> +20 testfile
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="less" tabindex="-1"><a class="header-anchor" href="#less" aria-hidden="true">#</a> less</h2><p><code>less</code>可以随意浏览文件，支持翻页和搜索，支持向上翻页和向下翻页。</p><h4 id="语法-8" tabindex="-1"><a class="header-anchor" href="#语法-8" aria-hidden="true">#</a> 语法</h4><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">less</span> <span class="token punctuation">[</span>参数<span class="token punctuation">]</span> 文件
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li>参数说明 <ul><li><code>-b</code> &lt;缓冲区大小&gt; 设置缓冲区的大小</li><li><code>-e</code> 当文件显示结束后，自动离开</li><li><code>-f</code> 强迫打开特殊文件，例如外围设备代号、目录和二进制文件</li><li><code>-g</code> 只标志最后搜索的关键词</li><li><code>-i</code> 忽略搜索时的大小写</li><li><code>-m</code> 显示类似 more 命令的百分比</li><li><code>-N</code> 显示每行的行号</li><li><code>-o</code> &lt;文件名&gt; 将<code>less</code>输出的内容在指定文件中保存起来</li><li><code>-Q</code> 不使用警告音</li><li><code>-s</code> 显示连续空行为一行</li><li><code>-S</code> 行过长时间将超出部分舍弃</li><li><code>-x</code> &lt;数字&gt; 将&quot;tab&quot;键显示为规定的数字空格</li><li><code>/字符串</code>：向下搜索&quot;字符串&quot;的功能</li><li><code>?字符串</code>：向上搜索&quot;字符串&quot;的功能</li><li><code>n</code>：重复前一个搜索（与 / 或 ? 有关）</li><li><code>N</code>：反向重复前一个搜索（与 / 或 ? 有关）</li><li><code>b</code> 向上翻一页</li><li><code>d</code> 向后翻半页</li><li><code>h</code> 显示帮助界面</li><li><code>Q</code> 退出 less 命令</li><li><code>u</code> 向前滚动半页</li><li><code>y</code> 向前滚动一行</li><li><code>空格键</code> 滚动一页</li><li><code>回车键</code> 滚动一行</li><li><code>[pagedown]</code>： 向下翻动一页</li><li><code>[pageup]</code>： 向上翻动一页</li></ul></li><li>快捷键 <ul><li>1.全屏导航 <ul><li><code>ctrl + F</code> - 向前移动一屏</li><li><code>ctrl + B</code> - 向后移动一屏</li><li><code>ctrl + D</code> - 向前移动半屏</li><li><code>ctrl + U</code> - 向后移动半屏</li></ul></li><li>2.单行导航 <ul><li><code>j</code> - 下一行</li><li><code>k</code> - 上一行</li></ul></li><li>3.其它导航 <ul><li><code>G</code> - 移动到最后一行</li><li><code>g</code> - 移动到第一行</li><li><code>q / ZZ</code> - 退出<code>less</code>命令</li></ul></li><li>4.其它有用的命令 <ul><li><code>v</code> - 使用配置的编辑器编辑当前文件</li><li><code>h</code> - 显示<code>less</code>的帮助文档</li><li><code>&amp;pattern</code> - 仅显示匹配模式的行，而不是整个文件</li></ul></li><li>5.标记导航 <ul><li><code>ma</code> - 使用<code>a</code>标记文本的当前位置</li><li><code>&#39;a</code> - 导航到标记<code>a</code>处</li></ul></li></ul></li></ul><h4 id="实例-5" tabindex="-1"><a class="header-anchor" href="#实例-5" aria-hidden="true">#</a> 实例</h4><p>查看文件</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">less</span> log2013.log
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><code>ps</code>查看进程信息并通过<code>less</code>分页显示</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">ps</span> <span class="token parameter variable">-ef</span> <span class="token operator">|</span> <span class="token function">less</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="tail" tabindex="-1"><a class="header-anchor" href="#tail" aria-hidden="true">#</a> tail</h2><p>用于查看文件的内容</p><h4 id="语法-9" tabindex="-1"><a class="header-anchor" href="#语法-9" aria-hidden="true">#</a> 语法</h4><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">tail</span> <span class="token punctuation">[</span>参数<span class="token punctuation">]</span> <span class="token punctuation">[</span>文件<span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li><code>-f</code> 循环读取</li><li><code>-q</code> 不显示处理信息</li><li><code>-v</code> 显示详细的处理信息</li><li><code>-c&lt;数目&gt;</code> 显示的字节数</li><li><code>-n&lt;行数&gt;</code> 显示文件的尾部 n 行内容</li><li><code>--pid=PID</code> 与<code>-f</code>合用,表示在进程 ID,PID 死掉之后结束</li><li><code>-q, --quiet, --silent</code> 从不输出给出文件名的首部</li><li><code>-s, --sleep-interval=S</code> 与<code>-f</code>合用,表示在每次反复的间隔休眠 S 秒</li></ul><h4 id="实例-6" tabindex="-1"><a class="header-anchor" href="#实例-6" aria-hidden="true">#</a> 实例</h4><p>要显示<code>notes.log</code>文件的最后 10 行，请输入以下命令：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">tail</span> notes.log         <span class="token comment"># 默认显示最后 10 行</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>要跟踪名为<code>notes.log</code>的文件的增长情况，请输入以下命令：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">tail</span> <span class="token parameter variable">-f</span> notes.log
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>此命令显示<code>notes.log</code>文件的最后 10 行。当将某些行添加至<code>notes.log</code>文件时，<code>tail</code>命令会继续显示这些行。 显示一直继续，直到您按下（Ctrl-C）组合键停止显示。</p><p>显示文件<code>notes.log</code>的内容，从第 20 行至文件末尾:</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">tail</span> <span class="token parameter variable">-n</span> +20 notes.log
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>显示文件<code>notes.log</code>的最后 10 个字符:</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">tail</span> <span class="token parameter variable">-c</span> <span class="token number">10</span> notes.log
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="rm" tabindex="-1"><a class="header-anchor" href="#rm" aria-hidden="true">#</a> rm</h2><p>命令用于删除一个文件或者目录。</p><h4 id="语法-10" tabindex="-1"><a class="header-anchor" href="#语法-10" aria-hidden="true">#</a> 语法</h4><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">rm</span> <span class="token punctuation">[</span>options<span class="token punctuation">]</span> name<span class="token punctuation">..</span>.
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li><code>-i</code> 删除前逐一询问确认。</li><li><code>-f</code> 即使原档案属性设为唯读，亦直接删除，无需逐一确认。</li><li><code>-r</code> 将目录及以下之档案亦逐一删除。</li></ul><h4 id="实例-7" tabindex="-1"><a class="header-anchor" href="#实例-7" aria-hidden="true">#</a> 实例</h4><p>删除当前目录下的所有文件及目录，命令行为：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">rm</span>  <span class="token parameter variable">-r</span>  *
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="cp" tabindex="-1"><a class="header-anchor" href="#cp" aria-hidden="true">#</a> cp</h2><p>命令主要用于复制文件或目录。</p><h4 id="语法-11" tabindex="-1"><a class="header-anchor" href="#语法-11" aria-hidden="true">#</a> 语法</h4><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">cp</span> <span class="token punctuation">[</span>options<span class="token punctuation">]</span> 源文件 目标文件
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li><code>-a</code>：此选项通常在复制目录时使用，它保留链接、文件属性，并复制目录下的所有内容。其作用等于 dpR 参数组合。</li><li><code>-d</code>：复制时保留链接。这里所说的链接相当于 Windows 系统中的快捷方式。</li><li><code>-r</code> 或 <code>--recursive</code>：用于复制目录及其所有的子目录和文件，如果要复制目录，需要使用该选项。</li><li><code>-i</code> 或 <code>--interactive</code>：在复制前提示确认，如果目标文件已存在，则会询问是否覆盖，回答 y 时目标文件将被覆盖。。</li><li><code>-u</code> 或 <code>--update</code>：仅复制源文件中更新时间较新的文件。</li><li><code>-v</code> 或 <code>--verbose</code>：显示详细的复制过程。</li><li><code>-p</code> 或 <code>--preserve</code>：保留源文件的权限、所有者和时间戳信息。</li><li><code>-f</code> 或 <code>--force</code>：强制复制，即使目标文件已存在也会覆盖，而且不给出提示。</li><li><code>-l</code>：不复制文件，只是生成链接文件。</li></ul><h4 id="实例-8" tabindex="-1"><a class="header-anchor" href="#实例-8" aria-hidden="true">#</a> 实例</h4><p>将文件<code>file.txt</code>复制到目录<code>/path/to/destination/</code>中：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">cp</span> file.txt /path/to/destination/
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>使用指令<code>cp</code>将当前目录<code>test/</code>下的所有文件复制到新目录<code>newtest</code>下，输入如下命令：<br> 注意：用户使用该指令复制目录时，必须使用参数<code>-r</code>或者<code>-R</code></p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">cp</span> –r test/ newtest
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>复制文件，并在目标文件已存在时进行确认：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">cp</span> <span class="token parameter variable">-i</span> file.txt /path/to/destination/
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="mv" tabindex="-1"><a class="header-anchor" href="#mv" aria-hidden="true">#</a> mv</h2><p>命令用来为文件或目录改名、或将文件或目录移入其它位置。</p><h4 id="语法-12" tabindex="-1"><a class="header-anchor" href="#语法-12" aria-hidden="true">#</a> 语法</h4><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">mv</span> <span class="token punctuation">[</span>options<span class="token punctuation">]</span> <span class="token builtin class-name">source</span> dest
<span class="token function">mv</span> <span class="token punctuation">[</span>options<span class="token punctuation">]</span> source<span class="token punctuation">..</span>. directory
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><code>-b</code>: 当目标文件或目录存在时，在执行覆盖前，会为其创建一个备份。</li><li><code>-i</code>: 如果指定移动的源目录或文件与目标的目录或文件同名，则会先询问是否覆盖旧文件，输入<code>y</code>表示直接覆盖，输入<code>n</code>表示取消该操作。</li><li><code>-f</code>: 如果指定移动的源目录或文件与目标的目录或文件同名，不会询问，直接覆盖旧文件。</li><li><code>-n</code>: 不要覆盖任何已存在的文件或目录。</li><li><code>-u</code>：当源文件比目标文件新或者目标文件不存在时，才执行移动操作。</li></ul><table><thead><tr><th style="text-align:left;">命令格式</th><th style="text-align:center;">运行结果</th></tr></thead><tbody><tr><td style="text-align:left;"><code>mv source_file(文件) dest_file(文件)</code></td><td style="text-align:center;">将源文件名 source_file 改为目标文件名 dest_file</td></tr><tr><td style="text-align:left;"><code>mv source_file(文件) dest_directory(目录)</code></td><td style="text-align:center;">将文件 source_file 移动到目标目录 dest_directory 中</td></tr><tr><td style="text-align:left;"><code>mv source_directory(目录) dest_directory(目录)</code></td><td style="text-align:center;">目录名 dest_directory 已存在，将 source_directory 移动到目录名 dest_directory 中；目录名 dest_directory 不存在则 source_directory 改名为目录名 dest_directory</td></tr><tr><td style="text-align:left;"><code>mv source_directory(目录) dest_file(文件)</code></td><td style="text-align:center;">出错</td></tr></tbody></table><h2 id="ln" tabindex="-1"><a class="header-anchor" href="#ln" aria-hidden="true">#</a> ln</h2><p>为某一个文件在另外一个位置建立一个同步的链接。当我们需要在不同的目录，用到相同的文件时，我们不需要在每一个需要的目录下都放一个必须相同的文件，我们只要在某个固定的目录，放上该文件，然后在 其它的目录下用 ln 命令链接（link）它就可以，不必重复的占用磁盘空间。</p><ul><li>软链接： <ul><li>1.软链接，以路径的形式存在。类似于 Windows 操作系统中的快捷方式</li><li>2.软链接可以 跨文件系统，硬链接不可以</li><li>3.软链接可以对一个不存在的文件名进行链接</li><li>4.软链接可以对目录进行链接</li></ul></li><li>硬链接： <ul><li>1.硬链接，以文件副本的形式存在。但不占用实际空间。</li><li>2.不允许给目录创建硬链接</li><li>3.硬链接只有在同一个文件系统中才能创建</li></ul></li></ul><h4 id="语法-13" tabindex="-1"><a class="header-anchor" href="#语法-13" aria-hidden="true">#</a> 语法</h4><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">ln</span> <span class="token punctuation">[</span>参数<span class="token punctuation">]</span><span class="token punctuation">[</span>源文件或目录<span class="token punctuation">]</span><span class="token punctuation">[</span>目标文件或目录<span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li>必要参数 <ul><li><code>--backup[=CONTROL]</code> 备份已存在的目标文件</li><li><code>-b</code> 类似<code>--backup</code>，但不接受参数</li><li><code>-d</code> 允许超级用户制作目录的硬链接</li><li><code>-f</code> 强制执行</li><li><code>-i</code> 交互模式，文件存在则提示用户是否覆盖</li><li><code>-n</code> 把符号链接视为一般目录</li><li><code>-s</code> 软链接(符号链接)</li><li><code>-v</code> 显示详细的处理过程</li></ul></li><li>选择参数： <ul><li><code>-S</code> &quot;-S&lt;字尾备份字符串&gt;&quot;或<code>--suffix=&lt;字尾备份字符串&gt;</code></li><li><code>-V</code> &quot;-V&lt;备份方式&gt;&quot;或<code>--version-control=&lt;备份方式&gt;</code></li><li><code>--help</code> 显示帮助信息</li><li><code>--version</code> 显示版本信息</li></ul></li></ul><h4 id="实例-9" tabindex="-1"><a class="header-anchor" href="#实例-9" aria-hidden="true">#</a> 实例</h4><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">ln</span> <span class="token parameter variable">-s</span> log2013.log link2013
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="find" tabindex="-1"><a class="header-anchor" href="#find" aria-hidden="true">#</a> find</h2><p>用于在指定目录下查找文件和目录。</p><h4 id="语法-14" tabindex="-1"><a class="header-anchor" href="#语法-14" aria-hidden="true">#</a> 语法</h4><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">find</span> <span class="token punctuation">[</span>路径<span class="token punctuation">]</span> <span class="token punctuation">[</span>匹配条件<span class="token punctuation">]</span> <span class="token punctuation">[</span>动作<span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li>路径 是要查找的目录路径，可以是一个目录或文件名，也可以是多个路径，多个路径之间用空格分隔，如果未指定路径，则默认为当前目录。</li><li>expression 是可选参数，用于指定查找的条件，可以是文件名、文件类型、文件大小等等。 <ul><li><code>-name pattern</code>：按文件名查找，支持使用通配符 * 和 ?。</li><li><code>-type type</code>：按文件类型查找，可以是 f（普通文件）、d（目录）、l（符号链接）等。</li><li><code>-size [+-]size[cwbkMG]</code>：按文件大小查找，支持使用 + 或 - 表示大于或小于指定大小，单位可以是 c（字节）、w（字数）、b（块数）、k（KB）、M（MB）或 G（GB）。</li><li><code>-mtime days</code>：按修改时间查找，支持使用 + 或 - 表示在指定天数前或后，days 是一个整数表示天数。</li><li><code>-user username</code>：按文件所有者查找。</li><li><code>-group groupname</code>：按文件所属组查找。</li></ul></li><li>动作: 可选的，用于对匹配到的文件执行操作，比如删除、复制等。 <ul><li><code>-amin n</code>：查找在<code>n</code>分钟内被访问过的文件。</li><li><code>-atime n</code>：查找在<code>n*24</code>小时内被访问过的文件。</li><li><code>-cmin n</code>：查找在<code>n</code>分钟内状态发生变化的文件（例如权限）。</li><li><code>-ctime n</code>：查找在<code>n*24</code>小时内状态发生变化的文件（例如权限）。</li><li><code>-mmin n</code>：查找在<code>n</code>分钟内被修改过的文件。</li><li><code>-mtime n</code>：查找在<code>n*24</code>小时内被修改过的文件。</li></ul></li></ul><h4 id="实例-10" tabindex="-1"><a class="header-anchor" href="#实例-10" aria-hidden="true">#</a> 实例</h4><p>查找当前目录下名为 file.txt 的文件：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">find</span> <span class="token builtin class-name">.</span> <span class="token parameter variable">-name</span> file.txt
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>将当前目录及其子目录下所有文件后缀为 .c 的文件列出来:</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">find</span> <span class="token builtin class-name">.</span> <span class="token parameter variable">-name</span> <span class="token string">&quot;*.c&quot;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>将当前目录及其子目录中的所有文件列出：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">find</span> <span class="token builtin class-name">.</span> <span class="token parameter variable">-type</span> f
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>查找 /home 目录下大于 1MB 的文件：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">find</span> /home <span class="token parameter variable">-size</span> +1M
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>查找 /var/log 目录下在 7 天前修改过的文件：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">find</span> /var/log <span class="token parameter variable">-mtime</span> +7
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>查找过去 7 天内被访问的文件:</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">find</span> /path/to/search <span class="token parameter variable">-atime</span> <span class="token parameter variable">-7</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>在当前目录下查找最近 20 天内状态发生改变的文件和目录:</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">find</span> <span class="token builtin class-name">.</span> <span class="token parameter variable">-ctime</span>  <span class="token number">20</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>将当前目录及其子目录下所有 20 天前及更早更新过的文件列出:</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">find</span> <span class="token builtin class-name">.</span> <span class="token parameter variable">-ctime</span>  +20
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>查找 /var/log 目录中更改时间在 7 日以前的普通文件，并在删除之前询问它们：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">find</span> /var/log <span class="token parameter variable">-type</span> f <span class="token parameter variable">-mtime</span> +7 <span class="token parameter variable">-ok</span> <span class="token function">rm</span> <span class="token punctuation">{</span><span class="token punctuation">}</span> <span class="token punctuation">\\</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>查找当前目录中文件属主具有读、写权限，并且文件所属组的用户和其他用户具有读权限的文件：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">find</span> <span class="token builtin class-name">.</span> <span class="token parameter variable">-type</span> f <span class="token parameter variable">-perm</span> <span class="token number">644</span> <span class="token parameter variable">-exec</span> <span class="token function">ls</span> <span class="token parameter variable">-l</span> <span class="token punctuation">{</span><span class="token punctuation">}</span> <span class="token punctuation">\\</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>查找系统中所有文件长度为 0 的普通文件，并列出它们的完整路径：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">find</span> / <span class="token parameter variable">-type</span> f <span class="token parameter variable">-size</span> <span class="token number">0</span> <span class="token parameter variable">-exec</span> <span class="token function">ls</span> <span class="token parameter variable">-l</span> <span class="token punctuation">{</span><span class="token punctuation">}</span> <span class="token punctuation">\\</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>找并执行操作（例如删除）：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">find</span> /path/to/search <span class="token parameter variable">-name</span> <span class="token string">&quot;pattern&quot;</span> <span class="token parameter variable">-exec</span> <span class="token function">rm</span> <span class="token punctuation">{</span><span class="token punctuation">}</span> <span class="token punctuation">\\</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="diff" tabindex="-1"><a class="header-anchor" href="#diff" aria-hidden="true">#</a> diff</h2><p>用于比较文件的差异。diff 以逐行的方式，比较文本文件的异同处。如果指定要比较目录，则 diff 会比较目录中相同文件名的文件，但不会比较其中子目录。</p><h4 id="语法-15" tabindex="-1"><a class="header-anchor" href="#语法-15" aria-hidden="true">#</a> 语法</h4><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">diff</span> <span class="token punctuation">[</span>-abBcdefHilnNpPqrstTuvwy<span class="token punctuation">]</span><span class="token punctuation">[</span>-<span class="token operator">&lt;</span>行数<span class="token operator">&gt;</span><span class="token punctuation">]</span><span class="token punctuation">[</span>-C <span class="token operator">&lt;</span>行数<span class="token operator">&gt;</span><span class="token punctuation">]</span><span class="token punctuation">[</span>-D <span class="token operator">&lt;</span>巨集名称<span class="token operator">&gt;</span><span class="token punctuation">]</span><span class="token punctuation">[</span>-I <span class="token operator">&lt;</span>字符或字符串<span class="token operator">&gt;</span><span class="token punctuation">]</span><span class="token punctuation">[</span>-S <span class="token operator">&lt;</span>文件<span class="token operator">&gt;</span><span class="token punctuation">]</span><span class="token punctuation">[</span>-W <span class="token operator">&lt;</span>宽度<span class="token operator">&gt;</span><span class="token punctuation">]</span><span class="token punctuation">[</span>-x <span class="token operator">&lt;</span>文件或目录<span class="token operator">&gt;</span><span class="token punctuation">]</span><span class="token punctuation">[</span>-X <span class="token operator">&lt;</span>文件<span class="token operator">&gt;</span><span class="token punctuation">]</span><span class="token punctuation">[</span>--help<span class="token punctuation">]</span><span class="token punctuation">[</span>--left-column<span class="token punctuation">]</span><span class="token punctuation">[</span>--suppress-common-line<span class="token punctuation">]</span><span class="token punctuation">[</span>文件或目录1<span class="token punctuation">]</span><span class="token punctuation">[</span>文件或目录2<span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li>\`-&lt;行数&gt; 　指定要显示多少行的文本。此参数必须与-c 或-u 参数一并使用。</li><li><code>-a</code>或<code>--text</code> 　 diff 预设只会逐行比较文本文件。</li><li><code>-b</code>或<code>--ignore-space-change</code> 　不检查空格字符的不同。</li><li><code>-B</code>或<code>--ignore-blank-lines</code> 　不检查空白行。</li><li><code>-c</code> 　显示全部内文，并标出不同之处。</li><li><code>-C&lt;行数&gt;</code>或--context&lt;行数&gt; 　与执行&quot;-c-&lt;行数&gt;&quot;指令相同。</li><li><code>-d</code>或--minimal 　使用不同的演算法，以较小的单位来做比较。</li><li><code>-D&lt;巨集名称&gt;</code>或 ifdef&lt;巨集名称&gt; 　此参数的输出格式可用于前置处理器巨集。</li><li><code>-e</code>或<code>--ed</code> 　此参数的输出格式可用于 ed 的 script 文件。</li><li><code>-f</code>或<code>-forward-ed</code> 　输出的格式类似 ed 的 script 文件，但按照原来文件的顺序来显示不同处。</li><li><code>-H</code>或<code>--speed-large-files</code> 　比较大文件时，可加快速度。</li><li><code>-I&lt;字符或字符串&gt;</code>或--ignore-matching-lines&lt;字符或字符串&gt; 　若两个文件在某几行有所不同，而这几行同时都包含了选项中指定的字符或字符串，则不显示这两个文件的差异。</li><li><code>-i</code>或<code>--ignore-case</code> 　不检查大小写的不同。</li><li><code>-l</code>或<code>--paginate</code> 　将结果交由 pr 程序来分页。</li><li><code>-n</code>或<code>--rcs</code> 　将比较结果以 RCS 的格式来显示。</li><li><code>-N</code>或<code>--new-file</code> 　在比较目录时，若文件 A 仅出现在某个目录中，预设会显示：</li><li><code>Only in</code>目录：文件 A 若使用-N 参数，则 diff 会将文件 A 与一个空白的文件比较。</li><li><code>-p</code> 　若比较的文件为 C 语言的程序码文件时，显示差异所在的函数名称。</li><li><code>-P</code>或<code>--unidirectional-new-file</code> 　与<code>-N</code>类似，但只有当第二个目录包含了一个第一个目录所没有的文件时，才会将这个文件与空白的文件做比较。</li><li><code>-q</code>或<code>--brief</code> 　仅显示有无差异，不显示详细的信息。</li><li><code>-r</code>或<code>--recursive</code> 　比较子目录中的文件。</li><li><code>-s</code>或<code>--report-identical-files</code> 　若没有发现任何差异，仍然显示信息。</li><li><code>-S&lt;文件&gt;</code>或<code>--starting-file&lt;文件&gt;</code> 　在比较目录时，从指定的文件开始比较。</li><li><code>-t</code>或<code>--expand-tabs</code> 　在输出时，将 tab 字符展开。</li><li><code>-T</code>或<code>--initial-tab</code> 　在每行前面加上 tab 字符以便对齐。</li><li><code>-u</code>,<code>-U&lt;列数&gt;</code>或<code>--unified=&lt;列数&gt;</code> 　以合并的方式来显示文件内容的不同。</li><li><code>-v</code>或<code>--version</code> 　显示版本信息。</li><li><code>-w</code>或<code>--ignore-all-space</code> 　忽略全部的空格字符。</li><li><code>-W&lt;宽度&gt;</code>或<code>--width&lt;宽度&gt;</code> 　在使用<code>-y</code>参数时，指定栏宽。</li><li><code>-x&lt;文件名或目录&gt;</code>或<code>--exclude&lt;文件名或目录&gt;</code> 　不比较选项中所指定的文件或目录。</li><li><code>-X&lt;文件&gt;</code>或<code>--exclude-from&lt;文件&gt;</code> 　您可以将文件或目录类型存成文本文件，然后在=&lt;文件&gt;中指定此文本文件。</li><li><code>-y</code>或<code>--side-by-side</code> 　以并列的方式显示文件的异同之处。</li><li><code>--help</code> 　显示帮助。</li><li><code>--left-column</code> 　在使用-y 参数时，若两个文件某一行内容相同，则仅在左侧的栏位显示该行内容。</li><li><code>--suppress-common-lines</code> 　在使用<code>-y</code>参数时，仅显示不同之处。</li></ul><h4 id="实例-11" tabindex="-1"><a class="header-anchor" href="#实例-11" aria-hidden="true">#</a> 实例</h4><p>比较两个文件</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">diff</span> log2014.log log2013.log
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>并排格式输出</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">diff</span> log2014.log log2013.log  <span class="token parameter variable">-y</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="file" tabindex="-1"><a class="header-anchor" href="#file" aria-hidden="true">#</a> file</h2><p>用于辨识文件类型。</p><h4 id="语法-16" tabindex="-1"><a class="header-anchor" href="#语法-16" aria-hidden="true">#</a> 语法</h4><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">file</span> <span class="token punctuation">[</span>-bcLvz<span class="token punctuation">]</span><span class="token punctuation">[</span>-f <span class="token operator">&lt;</span>名称文件<span class="token operator">&gt;</span><span class="token punctuation">]</span><span class="token punctuation">[</span>-m <span class="token operator">&lt;</span>魔法数字文件<span class="token operator">&gt;</span><span class="token punctuation">..</span>.<span class="token punctuation">]</span><span class="token punctuation">[</span>文件或目录<span class="token punctuation">..</span>.<span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li><code>-b</code> 　列出辨识结果时，不显示文件名称。</li><li><code>-c</code> 　详细显示指令执行过程，便于排错或分析程序执行的情形。</li><li><code>-f&lt;名称文件&gt;</code> 　指定名称文件，其内容有一个或多个文件名称时，让 file 依序辨识这些文件，格式为每列一个文件名称。</li><li><code>-L</code> 　直接显示符号连接所指向的文件的类别。</li><li><code>-m&lt;魔法数字文件&gt;</code> 　指定魔法数字文件。</li><li><code>-v</code> 　显示版本信息。</li><li><code>-z</code> 　尝试去解读压缩文件的内容。</li><li><code>[文件或目录...]</code> 要确定类型的文件列表，多个文件之间使用空格分开，可以使用 shell 通配符匹配多个文件。</li></ul><h2 id="grep" tabindex="-1"><a class="header-anchor" href="#grep" aria-hidden="true">#</a> grep</h2><h4 id="语法-17" tabindex="-1"><a class="header-anchor" href="#语法-17" aria-hidden="true">#</a> 语法</h4><p>用于查找文件里符合条件的字符串或正则表达式。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">grep</span> <span class="token punctuation">[</span>options<span class="token punctuation">]</span> pattern <span class="token punctuation">[</span>files<span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>或</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">grep</span> <span class="token punctuation">[</span>-abcEFGhHilLnqrsvVwxy<span class="token punctuation">]</span><span class="token punctuation">[</span>-A<span class="token operator">&lt;</span>显示行数<span class="token operator">&gt;</span><span class="token punctuation">]</span><span class="token punctuation">[</span>-B<span class="token operator">&lt;</span>显示列数<span class="token operator">&gt;</span><span class="token punctuation">]</span><span class="token punctuation">[</span>-C<span class="token operator">&lt;</span>显示列数<span class="token operator">&gt;</span><span class="token punctuation">]</span><span class="token punctuation">[</span>-d<span class="token operator">&lt;</span>进行动作<span class="token operator">&gt;</span><span class="token punctuation">]</span><span class="token punctuation">[</span>-e<span class="token operator">&lt;</span>范本样式<span class="token operator">&gt;</span><span class="token punctuation">]</span><span class="token punctuation">[</span>-f<span class="token operator">&lt;</span>范本文件<span class="token operator">&gt;</span><span class="token punctuation">]</span><span class="token punctuation">[</span>--help<span class="token punctuation">]</span><span class="token punctuation">[</span>范本样式<span class="token punctuation">]</span><span class="token punctuation">[</span>文件或目录<span class="token punctuation">..</span>.<span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li><code>pattern</code> - 表示要查找的字符串或正则表达式。</li><li><code>files</code> - 表示要查找的文件名，可以同时查找多个文件，如果省略 files 参数，则默认从标准输入中读取数据。</li></ul><h4 id="常用选项" tabindex="-1"><a class="header-anchor" href="#常用选项" aria-hidden="true">#</a> 常用选项</h4><p><code>-i</code>：忽略大小写进行匹配。<br><code>-v</code>：反向查找，只打印不匹配的行。<br><code>-n</code>：显示匹配行的行号。<br><code>-r</code>：递归查找子目录中的文件。<br><code>-l</code>：只打印匹配的文件名。<br><code>-c</code>：只打印匹配的行数。</p><h4 id="实例-12" tabindex="-1"><a class="header-anchor" href="#实例-12" aria-hidden="true">#</a> 实例</h4><p>在文件 file.txt 中查找字符串 &quot;hello&quot;，并打印匹配的行：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">grep</span> hello file.txt
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>在文件夹 dir 中递归查找所有文件中匹配正则表达式 &quot;pattern&quot; 的行，并打印匹配行所在的文件名和行号：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">grep</span> <span class="token parameter variable">-r</span> <span class="token parameter variable">-n</span> pattern dir/
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>在标准输入中查找字符串 &quot;world&quot;，并只打印匹配的行数：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token builtin class-name">echo</span> <span class="token string">&quot;hello world&quot;</span> <span class="token operator">|</span> <span class="token function">grep</span> <span class="token parameter variable">-c</span> world
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>在当前目录中，查找后缀有 file 字样的文件中包含 test 字符串的文件，并打印出该字符串的行。此时，可以使用如下命令：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">grep</span> <span class="token builtin class-name">test</span> *file
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>以递归的方式查找符合条件的文件。例如，查找指定目录/etc/acpi 及其子目录（如果存在子目录的话）下所有文件中包含字符串&quot;update&quot;的文件，并打印出该字符串所在行的内容，使用的命令为：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">grep</span> <span class="token parameter variable">-r</span> update /etc/acpi
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>反向查找。前面各个例子是查找并打印出符合条件的行，通过&quot;-v&quot;参数可以打印出不符合条件行的内容。查找文件名中包含 test 的文件中不包含test 的行，此时，使用的命令为：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">grep</span> <span class="token parameter variable">-v</span> <span class="token builtin class-name">test</span> *test*
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="zip" tabindex="-1"><a class="header-anchor" href="#zip" aria-hidden="true">#</a> zip</h2><p>用于压缩文件。</p><h4 id="语法-18" tabindex="-1"><a class="header-anchor" href="#语法-18" aria-hidden="true">#</a> 语法</h4><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">zip</span> <span class="token punctuation">[</span>-AcdDfFghjJKlLmoqrSTuvVwXyz$<span class="token punctuation">]</span><span class="token punctuation">[</span>-b <span class="token operator">&lt;</span>工作目录<span class="token operator">&gt;</span><span class="token punctuation">]</span><span class="token punctuation">[</span>-ll<span class="token punctuation">]</span><span class="token punctuation">[</span>-n <span class="token operator">&lt;</span>字尾字符串<span class="token operator">&gt;</span><span class="token punctuation">]</span><span class="token punctuation">[</span>-t <span class="token operator">&lt;</span>日期时间<span class="token operator">&gt;</span><span class="token punctuation">]</span><span class="token punctuation">[</span>-<span class="token operator">&lt;</span>压缩效率<span class="token operator">&gt;</span><span class="token punctuation">]</span><span class="token punctuation">[</span>压缩文件<span class="token punctuation">]</span><span class="token punctuation">[</span>文件<span class="token punctuation">..</span>.<span class="token punctuation">]</span><span class="token punctuation">[</span>-i <span class="token operator">&lt;</span>范本样式<span class="token operator">&gt;</span><span class="token punctuation">]</span><span class="token punctuation">[</span>-x <span class="token operator">&lt;</span>范本样式<span class="token operator">&gt;</span><span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li><code>-A</code>:调整可执行的自动解压缩文件。</li><li><code>-b&lt;工作目录&gt;</code>:指定暂时存放文件的目录。</li><li><code>-c</code>:替每个被压缩的文件加上注释。</li><li><code>-d</code>:从压缩文件内删除指定的文件。</li><li><code>-D</code>:压缩文件内不建立目录名称。</li><li><code>-f</code>:更新现有的文件。</li><li><code>-F</code>:尝试修复已损坏的压缩文件。</li><li><code>-g</code>:将文件压缩后附加在既有的压缩文件之后，而非另行建立新的压缩文件。</li><li><code>-h</code>:在线帮助。</li><li><code>-i&lt;范本样式&gt;</code>:只压缩符合条件的文件。</li><li><code>-j</code>:只保存文件名称及其内容，而不存放任何目录名称。</li><li><code>-J</code>:删除压缩文件前面不必要的数据。</li><li><code>-k</code>:使用 MS-DOS 兼容格式的文件名称。</li><li><code>-l</code>:压缩文件时，把 LF 字符置换成 LF+CR 字符。</li><li><code>-ll</code>:压缩文件时，把 LF+CR 字符置换成 LF 字符。</li><li><code>-L</code>:显示版权信息。</li><li><code>-m</code>:将文件压缩并加入压缩文件后，删除原始文件，即把文件移到压缩文件中。</li><li><code>-n&lt;字尾字符串&gt;</code>:不压缩具有特定字尾字符串的文件。</li><li><code>-o</code>:以压缩文件内拥有最新更改时间的文件为准，将压缩文件的更改时间设成和该文件相同。</li><li><code>-q</code>:不显示指令执行过程。</li><li><code>-r</code>:递归处理，将指定目录下的所有文件和子目录一并处理。</li><li><code>-S</code>:包含系统和隐藏文件。</li><li><code>-t&lt;日期时间&gt;</code>:把压缩文件的日期设成指定的日期。</li><li><code>-T</code>:检查备份文件内的每个文件是否正确无误。</li><li><code>-u</code>:与<code>-f</code>参数类似，但是除了更新现有的文件外，也会将压缩文件中的其他文件解压缩到目录中。</li><li><code>-v</code>:显示指令执行过程或显示版本信息。</li><li><code>-V</code>:保存 VMS 操作系统的文件属性。</li><li><code>-w</code>:在文件名称里假如版本编号，本参数仅在 VMS 操作系统下有效。</li><li><code>-x&lt;范本样式&gt;</code>：压缩时排除符合条件的文件。</li><li><code>-X</code>:不保存额外的文件属性。</li><li><code>-y</code>:直接保存符号连接，而非该连接所指向的文件，本参数仅在 UNIX 之类的系统下有效。</li><li><code>-z</code>:替压缩文件加上注释。</li><li><code>-$</code>:保存第一个被压缩文件所在磁盘的卷册名称。</li><li><code>-&lt;压缩效率&gt;</code>:压缩效率是一个介于 1-9 的数值。</li></ul><h4 id="实例-13" tabindex="-1"><a class="header-anchor" href="#实例-13" aria-hidden="true">#</a> 实例</h4><p>将 /home/html/ 这个目录下所有文件和文件夹打包为当前目录下的 html.zip：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">zip</span> <span class="token parameter variable">-q</span> <span class="token parameter variable">-r</span> html.zip /home/html
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>如果在我们在 /home/html 目录下，可以执行以下命令：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">zip</span> <span class="token parameter variable">-q</span> <span class="token parameter variable">-r</span> html.zip *
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>从压缩文件 cp.zip 中删除文件 a.c</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">zip</span> <span class="token parameter variable">-dv</span> cp.zip a.c
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="gzip" tabindex="-1"><a class="header-anchor" href="#gzip" aria-hidden="true">#</a> gzip</h2><p>用于压缩文件。</p><h4 id="语法-19" tabindex="-1"><a class="header-anchor" href="#语法-19" aria-hidden="true">#</a> 语法</h4><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">gzip</span> <span class="token punctuation">[</span>-acdfhlLnNqrtvV<span class="token punctuation">]</span><span class="token punctuation">[</span>-S <span class="token operator">&amp;</span>lt<span class="token punctuation">;</span>压缩字尾字符串<span class="token operator">&amp;</span>gt<span class="token punctuation">;</span><span class="token punctuation">]</span><span class="token punctuation">[</span>-<span class="token operator">&amp;</span>lt<span class="token punctuation">;</span>压缩效率<span class="token operator">&amp;</span>gt<span class="token punctuation">;</span><span class="token punctuation">]</span><span class="token punctuation">[</span>--best/fast<span class="token punctuation">]</span><span class="token punctuation">[</span>文件<span class="token punctuation">..</span>./目录<span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li><code>-a</code>或<code>--ascii</code>:使用 ASCII 文字模式。</li><li><code>-c</code>或<code>--stdout</code>或<code>--to-stdout</code>把压缩后的文件输出到标准输出设备，不去更动原始文件。</li><li><code>-d</code>或<code>--decompress</code>或<code>----uncompress</code>:解开压缩文件。</li><li><code>-f</code>或<code>--force</code>:强行压缩文件。不理会文件名称或硬连接是否存在以及该文件是否为符号连接。</li><li><code>-h</code>或<code>--help</code>:在线帮助。</li><li><code>-l</code>或<code>--list</code>:列出压缩文件的相关信息。</li><li><code>-L</code>或<code>--license</code>:显示版本与版权信息。</li><li><code>-n</code>或<code>--no-name</code>:压缩文件时，不保存原来的文件名称及时间戳记。</li><li><code>-N</code>或<code>--name</code>:压缩文件时，保存原来的文件名称及时间戳记。</li><li><code>-q</code>或<code>--quiet</code>:不显示警告信息。</li><li><code>-r</code>或<code>--recursive</code>:递归处理，将指定目录下的所有文件及子目录一并处理。</li><li><code>-S&lt;压缩字尾字符串&gt;</code>或<code>----suffix&lt;压缩字尾字符串&gt;</code>:更改压缩字尾字符串。</li><li><code>-t</code>或<code>--test</code>:测试压缩文件是否正确无误。</li><li><code>-v</code>或<code>--verbose</code>:显示指令执行过程。</li><li><code>-V</code>或<code>--version</code>:显示版本信息。</li><li><code>-&lt;压缩效率&gt;</code>：压缩效率是一个介于 1－9 的数值，预设值为&quot;6&quot;，指定愈大的数值，压缩效率就会愈高。</li><li><code>--best</code>：此参数的效果和指定&quot;-9&quot;参数相同。</li><li><code>--fast</code>:此参数的效果和指定&quot;-1&quot;参数相同。</li></ul><h4 id="实例-14" tabindex="-1"><a class="header-anchor" href="#实例-14" aria-hidden="true">#</a> 实例</h4><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">gzip</span> *
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h2 id="tar" tabindex="-1"><a class="header-anchor" href="#tar" aria-hidden="true">#</a> tar</h2><h4 id="语法-20" tabindex="-1"><a class="header-anchor" href="#语法-20" aria-hidden="true">#</a> 语法</h4><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">tar</span> <span class="token punctuation">[</span>选项<span class="token punctuation">]</span> <span class="token punctuation">[</span>压缩文件名<span class="token punctuation">]</span> <span class="token punctuation">[</span>文件或目录<span class="token punctuation">]</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h4 id="实例-15" tabindex="-1"><a class="header-anchor" href="#实例-15" aria-hidden="true">#</a> 实例</h4><p>创建归档文件：将文件 file1、file2 和 directory 打包到一个名为 archive.tar 的归档文件中。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">tar</span> <span class="token parameter variable">-cvf</span> archive.tar file1 file2 directory
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><code>-c</code>: 创建新的归档文件<br><code>-v</code>: 显示详细输出，列出被添加到归档中的文件<br><code>-f</code>: 指定归档文件的名称</p><p>解压归档文件：解压名为 archive.tar 的归档文件，还原其中包含的文件和目录。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">tar</span> <span class="token parameter variable">-xvf</span> archive.tar
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><code>-x</code>: 解压归档文件<br><code>-v</code>: 显示详细输出，列出被解压的文件<br><code>-f</code>: 指定要解压的归档文件的名称</p><p>列出归档文件中的内容：列出名为 archive.tar 的归档文件中包含的所有文件和目录。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">tar</span> <span class="token parameter variable">-tvf</span> archive.tar
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><code>-t</code>: 列出归档文件中的内容<br><code>-v</code>: 显示详细输出，列出归档文件中的所有文件和目录<br><code>-f</code>: 指定要列出内容的归档文件的名称</p><p>追加文件到已存在的归档中：将名为 newfile 的文件添加到已存在的名为 archive.tar 的归档文件中。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">tar</span> <span class="token parameter variable">-rvf</span> archive.tar newfile
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><code>-r</code>: 向已存在的归档中追加文件<br><code>-v</code>: 显示详细输出，列出被添加到归档中的文件<br><code>-f</code>: 指定已存在的归档文件的名称</p><p>创建一个经过 gzip 压缩的归档文件：打包 directory 目录下的所有文件和子目录，并使用 gzip 压缩，生成名为 archive.tar.gz 的归档文件。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">tar</span> <span class="token parameter variable">-zcvf</span> archive.tar.gz directory
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><code>-z</code>: 表示要使用 gzip 进行压缩。<br><code>-c</code>: 表示创建新的归档文件。<br><code>-v</code>: 表示详细输出，列出被添加到归档中的文件。<br><code>-f</code> archive.tar.gz: 指定归档文件的名称为 archive.tar.gz。</p><p>解压一个已经被 gzip 压缩的归档文件：解压 example.tar.gz 文件，并在当前目录下恢复其中包含的文件和目录。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">tar</span> <span class="token parameter variable">-zxvf</span> example.tar.gz
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><code>-z</code>: 表示要使用 gzip 解压归档文件。<br><code>-x</code>: 表示解压操作。<br><code>-v</code>: 表示详细输出，列出被解压的文件。<br><code>-f example.tar.gz</code>: 指定要解压的归档文件的名称为 example.tar.gz。</p>`,262),d=[i];function l(o,t){return a(),s("div",null,d)}const u=e(c,[["render",l],["__file","04.目录与文件.html.vue"]]);export{u as default};
